def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers):
    if not unvisited_customers:
        return None

    def distance(p1, p2):
        return np.linalg.norm(p1 - p2)

    def total_time_if_visiting(customer_index):
        # Calculate distance for current truck to this customer
        current_to_cust = distance(cur_truck_pos, unvisited_customers[customer_index])

        # Calculate return distance to depot
        return_to_depot = distance(unvisited_customers[customer_index], depot_pos)

        # Calculate time assuming all trucks wait for this truck to finish its route
        max_time = 0
        for truck_pos in all_truck_pos:
            truck_to_cust = distance(truck_pos, unvisited_customers[customer_index])
            truck_to_depot = distance(truck_pos, depot_pos)
            max_time = max(max_time, truck_to_cust + truck_to_depot)

        return current_to_cust + return_to_depot + max_time

    best_node = 0
    min_time = float('inf')

    for i in range(len(unvisited_customers)):
        route_time = total_time_if_visiting(i)
        if route_time < min_time:
            min_time = route_time
            best_node = i

    return best_node

import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers):
    def calculate_distance(pos1, pos2):
        return np.linalg.norm(pos1 - pos2)

    def max_finish_time(pos, customer_idx):
        mod_positions = all_truck_pos.copy()
        mod_positions.append(unvisited_customers[customer_idx])
        distances = [calculate_distance(pos, depot_pos) + calculate_distance(unvisited_customers[customer_idx], depot_pos) for pos in mod_positions]
        return max(distances)

    if not unvisited_customers:
        return None

    current_max_time = max(calculate_distance(truck_pos, depot_pos) for truck_pos in all_truck_pos)
    best_node, min_max_time = None, float('inf')

    for i, customer in enumerate(unvisited_customers):
        est_time = max_finish_time(cur_truck_pos, i)
        if est_time < current_max_time:
            return i
        if est_time < min_max_time:
            min_max_time = est_time
            best_node = i

    return best_node
